// Payload: tenant_id, source (conversation_summary), conversation_id
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const tenantId = body.tenant_id;
const source = body.source || 'conversation_summary';
const conversationId = body.conversation_id;
if (!tenantId || !conversationId) {
  throw new Error('tenant_id e conversation_id são obrigatórios');
}
return [{ json: { tenant_id: tenantId, source, conversation_id: conversationId } }];

